"""
This module contains the core game logic for Checkers.
"""

class Piece:
    def __init__(self, color, position):
        self.color = color
        self.position = position
        self.type = 'p' if self.color == 'b' else 'P'

    def __repr__(self):
        return f"{self.color}{self.type}"

class Board:
    def __init__(self):
        self.board = [[None] * 8 for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        # Initialize the board with pieces
        for row in range(3):
            for col in range((row + 1) % 2, 8, 2):
                self.board[row][col] = Piece('b', (row, col))
        for row in range(5, 8):
            for col in range((row + 1) % 2, 8, 2):
                self.board[row][col] = Piece('w', (row, col))

    def print_board(self):
        for row in self.board:
            print(" ".join(str(piece) if piece else '.' for piece in row))
        print()

class Game:
    def __init__(self):
        self.board = Board()
        self.current_player = 'b'

    def switch_turn(self):
        self.current_player = 'w' if self.current_player == 'b' else 'b'

    def move_piece(self, from_pos, to_pos):
        piece = self.board.board[from_pos[0]][from_pos[1]]
        self.board.board[to_pos[0]][to_pos[1]] = piece
        self.board.board[from_pos[0]][from_pos[1]] = None

    def is_valid_move(self, from_pos, to_pos):
        # Simple validation for demonstration purposes
        piece = self.board.board[from_pos[0]][from_pos[1]]
        return piece and self.current_player == piece.color and (to_pos[0], to_pos[1]) in self.get_legal_moves(from_pos)

    def get_legal_moves(self, from_pos):
        piece = self.board.board[from_pos[0]][from_pos[1]]
        moves = []
        if piece.type == 'p':
            if piece.color == 'b':
                move = (from_pos[0] + 1, from_pos[1] - 1)
                if move[1] >= 0 and self.board.board[move[0]][move[1]] is None:
                    moves.append(move)
                move = (from_pos[0] + 1, from_pos[1] + 1)
                if move[1] < 8 and self.board.board[move[0]][move[1]] is None:
                    moves.append(move)
            else:
                move = (from_pos[0] - 1, from_pos[1] - 1)
                if move[1] >= 0 and self.board.board[move[0]][move[1]] is None:
                    moves.append(move)
                move = (from_pos[0] - 1, from_pos[1] + 1)
                if move[1] < 8 and self.board.board[move[0]][move[1]] is None:
                    moves.append(move)
        return moves

    def is_game_over(self):
        # Simple check for demonstration purposes
        return not any(self.get_legal_moves((i, j)) for i in range(8) for j in range(8))

def main():
    game = Game()
    while True:
        game.board.print_board()
        move_from = input(f"Player {game.current_player}, enter move (from-to): ")
        if move_from == 'exit':
            break
        from_pos = tuple(map(int, move_from.split()))
        to_pos = tuple(map(int, input("Enter destination: ").split()))
        if game.is_valid_move(from_pos, to_pos):
            game.move_piece(from_pos, to_pos)
            game.switch_turn()
            if game.is_game_over():
                print(f"Player {game.current_player} wins!")
                break
        else:
            print("Invalid move. Try again.")

if __name__ == "__main__":
    main()
